        const formatCurrency = (value, currency = 'USD') => {
            return new Intl.NumberFormat('en-US', {
                style: 'currency',
                currency: currency,
                minimumFractionDigits: 2,
                maximumFractionDigits: value < 1 ? 6 : 2
            }).format(value);
        };

