            if not eligibility.get("eligible", False):
                return ClaimResult(
                    status=ClaimStatus.FAILED,
                    message=eligibility.get("message", "Not eligible for rewards")
                )

            # Prepare claim request
            claim_data = {
                "wallet_address": self.wallet_address,
                "timestamp": int(time.time())
            }

            # Send claim request
