        if (txIndex !== -1 && pathParts[txIndex + 1]) {
          const txId = pathParts[txIndex + 1].split('?')[0];
          if (/^[a-fA-F0-9]{64}$/.test(txId)) {
            return txId;
          }
        }
      }

