        });

        // Save results to file
        await saveResults(results);

        // Return results for programmatic use
        return results;

    } catch (error) {
        console.error('Error:', error.message);
        process.exit(1);
    }
}

// Export functions for testing and reuse
module.exports = {
    checkMatchAvailability,
